import React, { useState, useEffect } from 'react';
import { supabase } from './supabase';
import Login from './components/Login';
import Sidebar from './components/Sidebar';
import Dashboard from './components/Dashboard';
import Pedidos from './components/Pedidos';
import Productos from './components/Productos';
import Clientes from './components/Clientes';
import Reportes from './components/Reportes';
import { pedidosIniciales, productosIniciales, clientesIniciales, estadoConfig } from './datos';

function tocarCampana() {
  try {
    const ctx = new (window.AudioContext || window.webkitAudioContext)();
    const osc = ctx.createOscillator();
    const gain = ctx.createGain();
    osc.connect(gain); gain.connect(ctx.destination);
    osc.frequency.value = 880;
    gain.gain.setValueAtTime(0.3, ctx.currentTime);
    gain.gain.exponentialRampToValueAtTime(0.001, ctx.currentTime + 0.8);
    osc.start(); osc.stop(ctx.currentTime + 0.8);
  } catch(e) {}
}

export default function App() {
  const [session, setSession] = useState(null);
  const [cargando, setCargando] = useState(true);
  const [pagina, setPagina] = useState('dashboard');
  const [negocio, setNegocio] = useState(null);
  const [pedidos, setPedidos] = useState([]);
  const [productos, setProductos] = useState([]);
  const [notif, setNotif] = useState(null);

  const pedidosNuevos = pedidos.filter(p => p.estado === 'nuevo').length;

  useEffect(() => {
    supabase.auth.getSession().then(({ data: { session } }) => {
      setSession(session);
      setCargando(false);
    });
    const { data: { subscription } } = supabase.auth.onAuthStateChange((_event, session) => {
      setSession(session);
    });
    return () => subscription.unsubscribe();
  }, []);

  useEffect(() => {
    if (!session) return;
    supabase.from('negocios').select('*').eq('user_id', session.user.id).single()
      .then(({ data }) => { if (data) setNegocio(data); });

    const canal = supabase.channel('pedidos-nuevos')
      .on('postgres_changes', { event: 'INSERT', schema: 'public', table: 'pedidos' }, payload => {
        setPedidos(prev => [payload.new, ...prev]);
        setNotif(`Nuevo pedido de ${payload.new.cliente_nombre}`);
        tocarCampana();
        setTimeout(() => setNotif(null), 4000);
      }).subscribe();
    return () => supabase.removeChannel(canal);
  }, [session]);

  const cambiarEstado = async (id, nuevoEstado) => {
    setPedidos(prev => prev.map(p => p.id === id ? { ...p, estado: nuevoEstado } : p));
    await supabase.from('pedidos').update({ estado: nuevoEstado }).eq('id', id);
  };

  const cerrarSesion = () => supabase.auth.signOut();

  if (cargando) return (
    <div style={{ minHeight:'100vh', display:'flex', alignItems:'center', justifyContent:'center', background:'#F1F5F9' }}>
      <div style={{ fontSize:14, color:'#64748B' }}>Cargando...</div>
    </div>
  );

  if (!session) return <Login />;

  return (
    <div style={{ display:'flex', minHeight:'100vh' }}>
      <Sidebar pagina={pagina} setPagina={setPagina} pedidosNuevos={pedidosNuevos} negocio={negocio} onCerrarSesion={cerrarSesion} />
      <main style={{ flex:1, overflowY:'auto', background:'#F1F5F9' }}>
        {pagina==='dashboard' && <Dashboard pedidos={pedidos} setPagina={setPagina} />}
        {pagina==='pedidos'   && <Pedidos pedidos={pedidos} onCambiarEstado={cambiarEstado} />}
        {pagina==='productos' && <Productos productos={productos} setProductos={setProductos} negocioId={negocio?.id} />}
        {pagina==='clientes'  && <Clientes clientes={clientesIniciales} />}
        {pagina==='reportes'  && <Reportes pedidos={pedidos} productos={productos} />}
        {pagina==='config'    && (
          <div style={{ padding:'1.5rem' }}>
            <h1 style={{ fontSize:20, fontWeight:700, marginBottom:'1rem' }}>Configuración</h1>
            <div style={{ background:'#fff', borderRadius:12, padding:'1.25rem', maxWidth:480 }}>
              <div style={{ fontWeight:600, marginBottom:'1rem' }}>Datos del negocio</div>
              <p style={{ fontSize:14, color:'#64748B', marginBottom:'0.75rem' }}>Negocio: <strong>{negocio?.nombre || 'Sin nombre'}</strong></p>
              <p style={{ fontSize:14, color:'#64748B', marginBottom:'1.25rem' }}>Email: <strong>{session.user.email}</strong></p>
              <button onClick={cerrarSesion}
                style={{ padding:'8px 20px', borderRadius:8, border:'1px solid #FCA5A5', background:'#FEF2F2', color:'#DC2626', fontWeight:600, cursor:'pointer', fontSize:14 }}>
                Cerrar sesión
              </button>
            </div>
          </div>
        )}
      </main>

      {notif && (
        <div style={{ position:'fixed', top:20, right:20, background:'#1E293B', color:'#fff', padding:'12px 20px', borderRadius:12, fontSize:14, fontWeight:500, zIndex:9999 }}>
          🔔 {notif}
        </div>
      )}
    </div>
  );
}
